100	/**
101	 * Fetch issue title from GitHub using GitHubProvider.
102	 *
103	 * Returns placeholder if gh is not available or fetch fails.
104	 */
105	function fetchIssueTitle(issueNumber: number): string {
106	  return (
107	    ghProvider.fetchIssueTitleSync(String(issueNumber)) ??
108	    `(title unavailable for #${issueNumber})`
109	  );
110	}
111	
112	/**
113	 * Get detailed worktree information including branch names
114	 */
115	interface WorktreeInfo {
116	  path: string;
117	  branch: string;
118	  head: string;
119	}
120	
121	function getWorktreeDetails(): WorktreeInfo[] {
122	  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
123	    stdio: "pipe",
124	  });
125	
126	  if (result.status !== 0) {
127	    return [];
128	  }
129	
130	  const output = result.stdout.toString();
131	  const worktrees: WorktreeInfo[] = [];
132	  let current: Partial<WorktreeInfo> = {};
133	
134	  for (const line of output.split("\n")) {
135	    if (line.startsWith("worktree ")) {
136	      // Start of new worktree entry
137	      if (current.path) {
138	        worktrees.push(current as WorktreeInfo);
139	      }
140	      current = { path: line.substring(9) };
141	    } else if (line.startsWith("HEAD ")) {
142	      current.head = line.substring(5);
143	    } else if (line.startsWith("branch refs/heads/")) {
144	      current.branch = line.substring(18);
145	    } else if (line === "" && current.path) {
146	      // End of entry
147	      worktrees.push(current as WorktreeInfo);
148	      current = {};
149	    }
150	  }
151	
152	  // Don't forget the last entry
153	  if (current.path && current.branch) {
154	    worktrees.push(current as WorktreeInfo);
155	  }
156	
157	  return worktrees;
158	}
159	
160	/**
161	 * Infer the current phase for an issue by checking logs
162	 */
163	function inferPhaseFromLogs(issueNumber: number): Phase | undefined {
164	  const logPath = LOG_PATHS.project;
165	
166	  if (!fs.existsSync(logPath)) {
167	    return undefined;
168	  }
169	
170	  try {
171	    const files = fs.readdirSync(logPath).filter((f) => f.endsWith(".json"));
172	
173	    // Sort by timestamp (newest first)
174	    files.sort().reverse();
175	
176	    for (const file of files) {
177	      try {
178	        const content = fs.readFileSync(path.join(logPath, file), "utf-8");
179	        const logData = JSON.parse(content);
180	        const log = RunLogSchema.safeParse(logData);
181	
182	        if (!log.success) continue;
183	
184	        // Find this issue in the log
185	        const issueLog = log.data.issues.find(
186	          (i) => i.issueNumber === issueNumber,
187	        );
188	        if (issueLog && issueLog.phases.length > 0) {
189	          // Return the last executed phase
190	          const lastPhase = issueLog.phases[issueLog.phases.length - 1];
191	          return lastPhase.phase as Phase;
192	        }
193	      } catch {
194	        continue;
195	      }
196	    }
197	  } catch {
198	    return undefined;
199	  }
200	
201	  return undefined;
202	}
203	
204	/**
205	 * Discover worktrees that are not yet tracked in state
206	 *
207	 * Scans all git worktrees, identifies those with issue-related branch names,
208	 * and returns information about worktrees not yet in the state file.
209	 */
210	export async function discoverUntrackedWorktrees(
211	  options: DiscoverOptions = {},
212	): Promise<DiscoverResult> {
213	  try {
214	    const worktrees = getWorktreeDetails();
215	    const discovered: DiscoveredWorktree[] = [];
216	    const skipped: SkippedWorktree[] = [];
217	    let alreadyTracked = 0;
218	
219	    // Get existing state
220	    const manager = new StateManager({
221	      statePath: options.statePath,
222	      verbose: options.verbose,
223	    });
224	    const state = await manager.getState();
225	    const trackedIssues = new Set(
226	      Object.keys(state.issues).map((n) => parseInt(n, 10)),
227	    );
228	
229	    for (const worktree of worktrees) {
230	      // Skip if no branch (detached HEAD)
231	      if (!worktree.branch) {
232	        skipped.push({
233	          path: worktree.path,
234	          reason: "detached HEAD (no branch)",
235	        });
236	        continue;
237	      }
238	
239	      // Skip main/master branches
240	      if (worktree.branch === "main" || worktree.branch === "master") {
241	        skipped.push({
242	          path: worktree.path,
243	          reason: "main/master branch (not a feature worktree)",
244	        });
245	        continue;
246	      }
247	
248	      // Try to parse issue number from branch
249	      const issueNumber = parseIssueNumberFromBranch(worktree.branch);
250	      if (issueNumber === null) {
251	        skipped.push({
252	          path: worktree.path,
253	          reason: `branch name doesn't match issue pattern: ${worktree.branch}`,
254	        });
255	        continue;
