        expect(second.status).toBe(409);

        const body = JSON.parse(second.body);
        expect(body.error).toBe("conflict");
        expect(body.message).toContain("already connected");

        // Cleanup
        first.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 15000);

      describe("error handling", () => {
