          expect(body).toHaveProperty("error", "conflict");
          expect(body).toHaveProperty("message");
          expect(typeof body.message).toBe("string");
          expect(body.message.length).toBeGreaterThan(0);

          // Cleanup
          first.req.destroy();
          killProcessGroup(child, "SIGTERM");
        }, 15000);
      });
    });

